import React, { useEffect, useState } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { Card, Badge, Button, Spinner, Alert, ListGroup, Row, Col, ProgressBar } from 'react-bootstrap';
import { coverageApi, projectApi } from '../services/api';
import { CoverageReport, Project } from '../types';

interface FileInfo {
  filePath: string;
  lineCoverage: number;
  totalLines: number;
  coveredLines: number;
}

interface LineCoverage {
  lineNumber: number;
  isCovered: boolean;
  missedInstructions: number;
  coveredInstructions: number;
}

const ReportDetail: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [report, setReport] = useState<CoverageReport | null>(null);
  const [project, setProject] = useState<Project | null>(null);
  const [files, setFiles] = useState<FileInfo[]>([]);
  const [selectedFile, setSelectedFile] = useState<string | null>(null);
  const [fileCoverage, setFileCoverage] = useState<LineCoverage[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (id) {
      loadReport(parseInt(id));
    }
  }, [id]);

  const loadReport = async (reportId: number) => {
    try {
      setLoading(true);

      // 获取报告详情
      const reportRes = await coverageApi.getById(reportId);
      const reportData = reportRes.data.data;
      setReport(reportData);

      // 获取项目信息
      if (reportData) {
        const projectRes = await projectApi.getById(reportData.projectId);
        setProject(projectRes.data.data);

        // 获取文件列表
        const filesRes = await coverageApi.getFileCoverage(reportId, '');
        setFiles(filesRes.data.data || []);
      }

      setError(null);
    } catch (err) {
      setError('Failed to load report details');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleFileClick = async (filePath: string) => {
    try {
      setSelectedFile(filePath);
      const res = await coverageApi.getFileDetail(parseInt(id!), filePath);
      setFileCoverage(res.data.data?.lines || []);
    } catch (err) {
      console.error('Failed to load file coverage:', err);
    }
  };

  const getCoverageColor = (coverage: number) => {
    if (coverage >= 80) return 'success';
    if (coverage >= 60) return 'warning';
    return 'danger';
  };

  const getCoverageBadge = (coverage: number) => {
    const color = getCoverageColor(coverage);
    return <Badge bg={color}>{coverage.toFixed(1)}%</Badge>;
  };

  // 生成模拟代码内容（实际项目中应该从源代码仓库获取）
  const generateMockCode = (lineNumber: number): string => {
    const patterns = [
      `    fun processItem(item: Item${lineNumber}): Result {`,
      `        return if (item.id > ${lineNumber}) {`,
      `            Result.Success(item)`,
      `        } else {`,
      `            Result.Error("Invalid item")`,
      `        }`,
      `    }`,
      ``,
      `    val data${lineNumber} = loadData()`,
      `    processItem(data${lineNumber})`,
    ];
    return patterns[lineNumber % patterns.length] || `    // Line ${lineNumber}`;
  };

  if (loading) {
    return (
      <div className="text-center py-5">
        <Spinner animation="border" variant="primary" />
        <p className="mt-3 text-muted">Loading report details...</p>
      </div>
    );
  }

  if (!report) {
    return (
      <div>
        <Alert variant="danger">Report not found</Alert>
        <Button variant="primary" onClick={() => navigate('/reports')}>
          Back to Reports
        </Button>
      </div>
    );
  }

  return (
    <div>
      {/* Header */}
      <div className="d-flex justify-content-between align-items-center mb-4">
        <div>
          <h2 className="mb-1">Coverage Report Details</h2>
          <p className="text-muted mb-0">
            {project?.name} 
            <Badge bg={project?.platform === 'ios' ? 'dark' : 'success'} className="ms-2">
              {project?.platform}
            </Badge>
          </p>
        </div>
        <Button variant="outline-secondary" onClick={() => navigate(-1)}>
          ← Back
        </Button>
      </div>

      {error && <Alert variant="danger" dismissible onClose={() => setError(null)}>{error}</Alert>}

      {/* Report Info Card */}
      <Card className="border-0 shadow-sm mb-4">
        <Card.Header className="bg-primary text-white">
          <h5 className="mb-0">📊 Report Information</h5>
        </Card.Header>
        <Card.Body>
          <Row>
            <Col md={6}>
              <table className="table table-borderless">
                <tbody>
                  <tr>
                    <td className="text-muted">Report ID:</td>
                    <td><code>#{report.id}</code></td>
                  </tr>
                  <tr>
                    <td className="text-muted">Commit Hash:</td>
                    <td>
                      <code className="bg-light px-2 py-1 rounded">
                        {report.commitHash.substring(0, 7)}
                      </code>
                      <span className="text-muted ms-2">({report.commitHash})</span>
                    </td>
                  </tr>
                  <tr>
                    <td className="text-muted">Branch:</td>
                    <td>
                      <Badge bg="secondary">{report.branch}</Badge>
                    </td>
                  </tr>
                  <tr>
                    <td className="text-muted">Created At:</td>
                    <td>{new Date(report.createdAt).toLocaleString()}</td>
                  </tr>
                </tbody>
              </table>
            </Col>
            <Col md={6}>
              <h6 className="mb-3">Coverage Summary</h6>

              <div className="mb-3">
                <div className="d-flex justify-content-between mb-1">
                  <span>Line Coverage</span>
                  {getCoverageBadge(report.lineCoverage)}
                </div>
                <ProgressBar 
                  now={report.lineCoverage} 
                  variant={getCoverageColor(report.lineCoverage)}
                  style={{ height: '10px' }}
                />
              </div>

              <div className="mb-3">
                <div className="d-flex justify-content-between mb-1">
                  <span>Function Coverage</span>
                  {getCoverageBadge(report.functionCoverage)}
                </div>
                <ProgressBar 
                  now={report.functionCoverage} 
                  variant={getCoverageColor(report.functionCoverage)}
                  style={{ height: '10px' }}
                />
              </div>

              <div className="mb-3">
                <div className="d-flex justify-content-between mb-1">
                  <span>Branch Coverage</span>
                  {getCoverageBadge(report.branchCoverage)}
                </div>
                <ProgressBar 
                  now={report.branchCoverage} 
                  variant={getCoverageColor(report.branchCoverage)}
                  style={{ height: '10px' }}
                />
              </div>

              {report.incrementalCoverage !== undefined && (
                <div className="mt-3 pt-3 border-top">
                  <div className="d-flex justify-content-between mb-1">
                    <span>Incremental Coverage</span>
                    {getCoverageBadge(report.incrementalCoverage)}
                  </div>
                  <ProgressBar 
                    now={report.incrementalCoverage} 
                    variant={getCoverageColor(report.incrementalCoverage)}
                    style={{ height: '10px' }}
                  />
                </div>
              )}
            </Col>
          </Row>
        </Card.Body>
      </Card>

      {/* Files and Code View */}
      <Row>
        {/* File List */}
        <Col md={4}>
          <Card className="border-0 shadow-sm">
            <Card.Header className="bg-light">
              <h6 className="mb-0">📁 Files ({files.length})</h6>
            </Card.Header>
            <ListGroup variant="flush" style={{ maxHeight: '600px', overflowY: 'auto' }}>
              {files.length === 0 ? (
                <ListGroup.Item className="text-center text-muted py-4">
                  No files found
                </ListGroup.Item>
              ) : (
                files.map((file, index) => (
                  <ListGroup.Item
                    key={index}
                    action
                    active={selectedFile === file.filePath}
                    onClick={() => handleFileClick(file.filePath)}
                    className="d-flex justify-content-between align-items-center"
                  >
                    <div className="text-truncate" style={{ maxWidth: '70%' }}>
                      <small>{file.filePath.split('/').pop()}</small>
                    </div>
                    <Badge 
                      bg={getCoverageColor(file.lineCoverage)}
                      className="ms-2"
                    >
                      {file.lineCoverage.toFixed(0)}%
                    </Badge>
                  </ListGroup.Item>
                ))
              )}
            </ListGroup>
          </Card>
        </Col>

        {/* Code View */}
        <Col md={8}>
          <Card className="border-0 shadow-sm">
            <Card.Header className="bg-light d-flex justify-content-between align-items-center">
              <h6 className="mb-0">
                {selectedFile ? `📝 ${selectedFile.split('/').pop()}` : 'Select a file to view coverage'}
              </h6>
              {selectedFile && fileCoverage.length > 0 && (
                <div className="d-flex gap-2">
                  <Badge bg="success">✓ Covered</Badge>
                  <Badge bg="danger">✗ Uncovered</Badge>
                </div>
              )}
            </Card.Header>
            <Card.Body className="p-0">
              {selectedFile ? (
                fileCoverage.length > 0 ? (
                  <div 
                    className="code-viewer" 
                    style={{ 
                      maxHeight: '600px', 
                      overflow: 'auto',
                      fontFamily: 'monospace',
                      fontSize: '14px',
                      lineHeight: '1.5'
                    }}
                  >
                    {fileCoverage.map((line) => (
                      <div
                        key={line.lineNumber}
                        className={`d-flex ${
                          line.isCovered ? 'bg-success-subtle' : 'bg-danger-subtle'
                        }`}
                        style={{
                          borderLeft: `4px solid ${line.isCovered ? '#198754' : '#dc3545'}`,
                          padding: '2px 0'
                        }}
                      >
                        {/* Line Number */}
                        <div 
                          className="text-muted text-end pe-3"
                          style={{ 
                            minWidth: '50px', 
                            userSelect: 'none',
                            backgroundColor: 'rgba(0,0,0,0.03)'
                          }}
                        >
                          {line.lineNumber}
                        </div>

                        {/* Coverage Indicator */}
                        <div 
                          className="pe-2"
                          style={{ minWidth: '30px', textAlign: 'center' }}
                        >
                          {line.isCovered ? (
                            <span className="text-success">✓</span>
                          ) : (
                            <span className="text-danger">✗</span>
                          )}
                        </div>

                        {/* Code Content */}
                        <div className="flex-grow-1 ps-2" style={{ whiteSpace: 'pre' }}>
                          {generateMockCode(line.lineNumber)}
                        </div>

                        {/* Coverage Count */}
                        <div 
                          className="text-muted pe-3"
                          style={{ minWidth: '80px', textAlign: 'right', fontSize: '12px' }}
                        >
                          {line.coveredInstructions > 0 && (
                            <span className="text-success">+{line.coveredInstructions}</span>
                          )}
                          {line.missedInstructions > 0 && (
                            <span className="text-danger ms-1">-{line.missedInstructions}</span>
                          )}
                        </div>
                      </div>
                    ))}
                  </div>
                ) : (
                  <div className="text-center py-5 text-muted">
                    <Spinner animation="border" size="sm" className="me-2" />
                    Loading coverage data...
                  </div>
                )
              ) : (
                <div className="text-center py-5 text-muted">
                  <div className="mb-3">📄</div>
                  <p>Select a file from the list to view detailed coverage</p>
                </div>
              )}
            </Card.Body>
          </Card>

          {/* Legend */}
          {selectedFile && (
            <Card className="border-0 shadow-sm mt-3">
              <Card.Body className="py-2">
                <small className="text-muted">
                  <strong>Legend:</strong>
                  <span className="ms-3 text-success">✓ Covered</span>
                  <span className="ms-3 text-danger">✗ Uncovered</span>
                  <span className="ms-3 text-success">+N</span> Instructions covered
                  <span className="ms-3 text-danger">-N</span> Instructions missed
                </small>
              </Card.Body>
            </Card>
          )}
        </Col>
      </Row>
    </div>
  );
};

export default ReportDetail;
